import{_ as e,c as i,o as s,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Guía Rápida: Comienza con OpenSkills | OpenSkills","description":"Aprende los fundamentos de OpenSkills en minutos. Completa la instalación de herramientas y habilidades en 15 minutos, permitiendo que tus agentes de IA utilicen nuevas capacidades y comprendan su funcionamiento.","frontmatter":{"title":"Guía Rápida: Comienza con OpenSkills | OpenSkills","sidebarTitle":"Primeros pasos en 15 min","subtitle":"Guía Rápida: Comienza con OpenSkills | OpenSkills","description":"Aprende los fundamentos de OpenSkills en minutos. Completa la instalación de herramientas y habilidades en 15 minutos, permitiendo que tus agentes de IA utilicen nuevas capacidades y comprendan su funcionamiento.","order":1},"headers":[],"relativePath":"es/numman-ali/openskills/start/index.md","filePath":"es/numman-ali/openskills/start/index.md"}'),n={name:"es/numman-ali/openskills/start/index.md"};function d(t,a,r,o,p,c){return s(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="guia-rapida" tabindex="-1">Guía Rápida <a class="header-anchor" href="#guia-rapida" aria-label="Permalink to &quot;Guía Rápida&quot;">​</a></h1><p>Esta sección te ayuda a comenzar con OpenSkills, desde la instalación de herramientas hasta que tu agente de IA utilice habilidades, todo en solo 10-15 minutos.</p><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de aprendizaje&quot;">​</a></h2><p>Te recomendamos seguir este orden:</p><h3 id="_1-guia-rapida" tabindex="-1">1. <a href="./quick-start/">Guía Rápida</a> <a class="header-anchor" href="#_1-guia-rapida" aria-label="Permalink to &quot;1. [Guía Rápida](./quick-start/)&quot;">​</a></h3><p>Completa la instalación de herramientas, instalación de habilidades y sincronización en 5 minutos, experimentando el valor principal de OpenSkills.</p><ul><li>Instala la herramienta OpenSkills</li><li>Instala habilidades desde el repositorio oficial de Anthropic</li><li>Sincroniza habilidades a AGENTS.md</li><li>Verifica que el agente de IA puede utilizar las habilidades</li></ul><h3 id="_2-¿que-es-openskills" tabindex="-1">2. <a href="./what-is-openskills/">¿Qué es OpenSkills?</a> <a class="header-anchor" href="#_2-¿que-es-openskills" aria-label="Permalink to &quot;2. [¿Qué es OpenSkills?](./what-is-openskills/)&quot;">​</a></h3><p>Comprende los conceptos fundamentales y el funcionamiento de OpenSkills.</p><ul><li>La relación entre OpenSkills y Claude Code</li><li>Formato de habilidades unificado, carga progresiva, soporte multi-agente</li><li>Cuándo usar OpenSkills en lugar del sistema de habilidades integrado</li></ul><h3 id="_3-guia-de-instalacion" tabindex="-1">3. <a href="./installation/">Guía de instalación</a> <a class="header-anchor" href="#_3-guia-de-instalacion" aria-label="Permalink to &quot;3. [Guía de instalación](./installation/)&quot;">​</a></h3><p>Pasos detallados de instalación y configuración del entorno.</p><ul><li>Verificación de entorno Node.js y Git</li><li>Uso temporal con npx vs instalación global</li><li>Resolución de problemas comunes de instalación</li></ul><h3 id="_4-instala-tu-primera-habilidad" tabindex="-1">4. <a href="./first-skill/">Instala tu primera habilidad</a> <a class="header-anchor" href="#_4-instala-tu-primera-habilidad" aria-label="Permalink to &quot;4. [Instala tu primera habilidad](./first-skill/)&quot;">​</a></h3><p>Instala habilidades desde el repositorio oficial de Anthropic y experimenta la selección interactiva.</p><ul><li>Usa el comando <code>openskills install</code></li><li>Selección interactiva de habilidades necesarias</li><li>Comprende la estructura del directorio de habilidades (.claude/skills/)</li></ul><h3 id="_5-sincroniza-habilidades-a-agents-md" tabindex="-1">5. <a href="./sync-to-agents/">Sincroniza habilidades a AGENTS.md</a> <a class="header-anchor" href="#_5-sincroniza-habilidades-a-agents-md" aria-label="Permalink to &quot;5. [Sincroniza habilidades a AGENTS.md](./sync-to-agents/)&quot;">​</a></h3><p>Genera el archivo AGENTS.md para que tu agente de IA sepa qué habilidades están disponibles.</p><ul><li>Usa el comando <code>openskills sync</code></li><li>Comprende el formato XML de AGENTS.md</li><li>Selecciona qué habilidades sincronizar, controlando el tamaño del contexto</li></ul><h3 id="_6-usa-habilidades" tabindex="-1">6. <a href="./read-skills/">Usa habilidades</a> <a class="header-anchor" href="#_6-usa-habilidades" aria-label="Permalink to &quot;6. [Usa habilidades](./read-skills/)&quot;">​</a></h3><p>Entiende cómo los agentes de IA cargan el contenido de las habilidades.</p><ul><li>Usa el comando <code>openskills read</code></li><li>Orden de prioridad de búsqueda de habilidades (4 niveles)</li><li>Leer múltiples habilidades a la vez</li></ul><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><p>Antes de comenzar, asegúrate de tener:</p><ul><li><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 20.6.0 o superior instalado</li><li><a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> instalado (para instalar habilidades desde GitHub)</li><li>Al menos un agente de codificación con IA instalado (Claude Code, Cursor, Windsurf, Aider, etc.)</li></ul><div class="tip custom-block"><p class="custom-block-title">Verificación rápida del entorno</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Debería mostrar v20.6.0 o superior</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Debería mostrar git version x.x.x</span></span></code></pre></div></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes pasos&quot;">​</a></h2><p>Una vez completada esta sección, puedes continuar aprendiendo:</p><ul><li><a href="./../platforms/cli-commands/">Comandos en detalle</a>: Profundiza en todos los comandos y parámetros</li><li><a href="./../platforms/install-sources/">Fuentes de instalación en detalle</a>: Aprende a instalar habilidades desde GitHub, rutas locales, repositorios privados</li><li><a href="./../advanced/create-skills/">Crea habilidades personalizadas</a>: Crea tus propias habilidades personalizadas</li></ul>`,29)])])}const m=e(n,[["render",d]]);export{h as __pageData,m as default};
